#include <stdlib.h>
#include <stdio.h>


void sort(int * arr, int size) {
    int i;
    if (size < 6) {
        int nSize = 0;
        while (size != 0) {
            nSize = 0;
            for (i = 0; i < size - 1; i++) 
                if (arr[i] > arr[i + 1]) {
                    nSize = i + 1;
                    arr[i] ^= arr[i + 1];
                    arr[i + 1] ^= arr[i];
                    arr[i] ^= arr[i + 1];
                }
            size = nSize;
        }
        return;
    }
    int * tmp = (int *)calloc(size, sizeof(int));
    int lSize = (size >> 1);
    int rSize = size - lSize;
    sort(arr, lSize); sort(arr + lSize, rSize);
    int lPtr = 0, rPtr = 0;
    int ptr = 0;
    while (ptr != size) {
        if (lPtr == lSize)
            tmp[ptr] = arr[lSize + (rPtr++)];
        else if (rPtr == rSize || arr[lPtr] <= arr[lSize + rPtr])
            tmp[ptr] = arr[lPtr++];
        else
            tmp[ptr] = arr[lSize + (rPtr++)];
        ptr++;
    }
    for (i = 0; i < size; i++)
        arr[i] = tmp[i];
    free(tmp);
}

int main(void) {
    int n, i, t1, t2;
    scanf("%d ", &n);
    int arr1[n];
    int arr2[n];
    char c;
    for (i = 0; i < n; i++){
        scanf("%c", &c);
        arr1[i] = c - '0';
    }
    for (i = 0; i < n; i++){
        scanf("%c", &c);
        arr2[i] = c - '0';
    }
    sort(arr1, n);
    sort(arr2, n);
    t1 = 1;
    t2 = 1;
    for (i = 0; i < n; i++) {
        if (arr1[i] >= arr2[i])
            t1 = 0;
        if (arr1[i] <= arr2[i])
            t2 = 0;
    }
    printf("%s\n", (t1 || t2) ? "YES" : "NO");
    return 0;
}

