use std::io::stdin;

pub fn read_line() -> String {
    let mut buf = String::new();
    stdin().read_line(&mut buf).expect("Failed to read a line");
    buf
}

pub fn main() {
    let n: usize = read_line().trim().parse().unwrap();
    let mut a: Vec<u32> = read_line()
        .trim()
        .chars()
        .map(|x| x.to_digit(10).unwrap())
        .collect();
    let mut b = a.split_off(n);
    a.sort();
    b.sort();
    println!(
        "{}",
        if a.iter().zip(b.iter()).all(|(x, y)| x < y) || a.iter().zip(b.iter()).all(|(x, y)| x > y)
        {
            "YES"
        } else {
            "NO"
        }
    );
}
